aptixia.sm.DynamicGridControlEvent ev = i_arg1;
Route route = null;
try
{
    route = ev.DataList[ev.RowIndex] as Route;
}
catch
{
}

//Route route = ((aptixia.sm.DynamicGridControl)i_arg0).SelectedRow as Route;

if (route != null &&
    route.targetType == "host")
{
    long max = (route.protocol == "IPv4") ? 32 : 128;
    if (route.prefixLength != max)
        route.prefixLength = max;
}

aptixia.sm.DynamicGridControlEvent ev = i_arg1;
if (ev.FieldName != "destinationIp" &&
    ev.FieldName != "gateway")
{
    return;
}

aptixia.sm.DynamicGridControl control =
    (aptixia.sm.DynamicGridControl) i_arg0;
Route route;

try
{
    route = control.Collection[ev.RowIndex] as Route;
}
catch (ArgumentOutOfRangeException ex)
{
    return;
}

string address = ev.Data.ToString().Trim();
INetAddress addressObject;

try
{
    addressObject = AddressFactory.CreateAddress(address);
}
catch (Exception e)
{
    ev.Error = e.Message;
    return;
}

if (addressObject.TypeString() != route.protocol)
{
    ev.Error = "Protocol does not match address.";
    return;
}
